function renderStars(rating) {
  const rounded = Math.max(0, Math.min(5, Math.round(rating)));
  const stars = [];
  for (let i = 0; i < 5; i += 1) {
    stars.push(`<span class="star ${i < rounded ? "filled" : ""}">\u2605</span>`);
  }
  return stars.join("");
}
function renderProductCard(product, options = {}) {
  const {
    compact = false,
    showCategory = true,
    showDescription = true,
    compareMode = false,
    imageLoading = "eager",
    imageFetchPriority = ""
  } = options;
  const cardClass = compact ? "product-card compact" : compareMode ? "product-card compare-mode" : "product-card";
  const isSoldOut = product.stock <= 0;
  const isLowStock = !isSoldOut && product.stock <= 8;
  const stockText = isSoldOut ? "Ausverkauft" : isLowStock ? `Nur noch ${product.stock} verfuegbar` : `${product.stock} auf Lager`;
  const stockClass = isSoldOut ? "stock-state sold-out" : isLowStock ? "stock-state low-stock" : "stock-state in-stock";
  const utilityHighlight = product.features[0] || product.description;
  const experience = buildProductExperienceContent(product);
  const merchSignature = getProductMerchSignature(product, experience);
  const productContext = experience.useCases[0]?.title || product.category;
  const compareHint = discountPercent(product) > 0 ? `${discountPercent(product)}% unter UVP` : "Preis klar sichtbar";
  const effectiveShowCategory = compact ? false : showCategory;
  const effectiveShowDescription = compact ? false : showDescription;
  return `
<article class="${cardClass} ${merchSignature.themeClass}" data-product-card data-name="${escapeHtml(
    (product.name + " " + product.description).toLowerCase()
  )}" data-category="${escapeHtml(product.category)}" data-price="${product.priceEur}" data-rating="${product.rating}" data-stock="${product.stock}">
  <a href="/products/${product.slug}" class="product-image-wrap">
    ${renderResponsiveImage({ src: product.imageUrl, alt: product.name, loading: imageLoading, fetchpriority: imageFetchPriority, sizes: "(min-width: 1100px) 25vw, (min-width: 720px) 33vw, 92vw", width: 960, height: 960, srcsetWidths: [360, 540, 720, 960, 1280] })}
    <span class="product-badge">${escapeHtml(product.badge || "Empfohlen")}</span>
    <span class="product-mode-badge">${escapeHtml(merchSignature.mode)}</span>
    ${discountPercent(product) > 0 ? `<span class="product-discount">-${discountPercent(product)}%</span>` : ""}
  </a>

  <div class="product-body">
    ${effectiveShowCategory ? `<p class="product-category">${escapeHtml(product.category)}</p>` : ""}
    <a class="product-title" href="/products/${product.slug}">${escapeHtml(product.name)}</a>
    <div class="product-scene-row">
      <span>${escapeHtml(merchSignature.mode)}</span>
      <span>${escapeHtml(merchSignature.support)}</span>
    </div>

    ${effectiveShowDescription ? `<p class="product-copy">${escapeHtml(product.description)}</p>` : ""}

    <p class="product-utility">${escapeHtml(utilityHighlight)}</p>
    <div class="product-compare-line">
      <span>${escapeHtml(compareHint)}</span>
      <span>${formatPrice(product.priceEur)}</span>
    </div>
    <div class="product-context-row">
      <span>${escapeHtml(productContext)}</span>
      <span>${compareMode ? "Details & Preis" : "Mehr sehen"}</span>
    </div>

    ${compact ? `<div class="product-compact-meta">
      <span>24-48h Lieferung</span>
      <span>Rueckgabe klar</span>
    </div>` : `<div class="product-meta-line">
      <span class="stars">${renderStars(product.rating)}</span>
      <span>${product.rating.toFixed(1)} (${product.reviewCount})</span>
      <span class="${stockClass}">${stockText}</span>
    </div>
    <div class="product-trust">
      <span>24-48h Lieferung \xB7 Rueckgabe klar</span>
    </div>`}

    <div class="product-price-row">
      <div>
        <span class="old-price">${formatPrice(product.compareAtEur)}</span>
        <strong>${formatPrice(product.priceEur)}</strong>
      </div>
      <button type="button" class="btn-primary js-add-to-cart" data-product-id="${product.id}" aria-label="${escapeHtml(
    product.name
  )} in den Warenkorb legen"${isSoldOut ? ` disabled aria-disabled="true"` : ""}>${isSoldOut ? "Ausverkauft" : "In den Warenkorb"}</button>
    </div>
  </div>
</article>`;
}
