  function bindCatalogFilters() {
    const search = document.getElementById('catalogSearch');
    const sort = document.getElementById('catalogSort');
    const grid = document.getElementById('catalogGrid');
    const countNode = document.getElementById('catalogCount');
    const contextNode = document.getElementById('catalogContextNote');
    const resetButton = document.getElementById('catalogResetButton');
    const selectionStrip = document.getElementById('catalogSelectionStrip');
    const selectionEyebrow = document.getElementById('catalogSelectionEyebrow');
    const selectionTitle = document.getElementById('catalogSelectionTitle');
    const selectionGrid = document.getElementById('catalogSelectionGrid');
    const emptyState = document.getElementById('catalogEmptyState');
    const emptyResetButton = document.getElementById('catalogEmptyResetButton');
    const chips = document.querySelectorAll('[data-category-filter]');
    const cards = Array.from(document.querySelectorAll('[data-product-card]'));

    if (!search || cards.length === 0 || chips.length === 0 || !grid) {
      return;
    }

    let activeCategory = 'all';

    function getSortValue() {
      return sort ? sort.value : 'featured';
    }

    function setActiveChip(value) {
      activeCategory = value;
      chips.forEach((node) => {
        const selected = (node.getAttribute('data-category-filter') || 'all') === value;
        node.classList.toggle('active', selected);
        node.setAttribute('aria-checked', selected ? 'true' : 'false');
        node.tabIndex = selected ? 0 : -1;
      });
    }

    function syncUrlState(query) {
      const params = new URLSearchParams(window.location.search);
      if (query) {
        params.set('q', query);
      } else {
        params.delete('q');
      }

      if (activeCategory !== 'all') {
        params.set('category', activeCategory);
      } else {
        params.delete('category');
      }

      const sortValue = getSortValue();
      if (sortValue !== 'featured') {
        params.set('sort', sortValue);
      } else {
        params.delete('sort');
      }

      const next = params.toString();
      const target = window.location.pathname + (next ? '?' + next : '');
      window.history.replaceState({}, '', target);
    }

    function resetFilters() {
      search.value = '';
      if (sort) {
        sort.value = 'featured';
      }
      setActiveChip('all');
      runFilter();
    }

    function compareCards(a, b, sortValue) {
      const priceA = Number.parseFloat(a.getAttribute('data-price') || '0');
      const priceB = Number.parseFloat(b.getAttribute('data-price') || '0');
      const ratingA = Number.parseFloat(a.getAttribute('data-rating') || '0');
      const ratingB = Number.parseFloat(b.getAttribute('data-rating') || '0');
      const nameA = (a.querySelector('.product-title')?.textContent || '').toLowerCase();
      const nameB = (b.querySelector('.product-title')?.textContent || '').toLowerCase();

      if (sortValue === 'price-asc') return priceA - priceB;
      if (sortValue === 'price-desc') return priceB - priceA;
      if (sortValue === 'rating-desc') return ratingB - ratingA;
      if (sortValue === 'name-asc') return nameA.localeCompare(nameB, 'de');
      return 0;
    }

    function renderSelectionStrip(visibleCards, query, hasFilters) {
      if (!selectionStrip || !selectionEyebrow || !selectionTitle || !selectionGrid) {
        return;
      }

      if (!hasFilters || visibleCards.length === 0) {
        selectionStrip.hidden = true;
        selectionGrid.innerHTML = '';
        return;
      }

      selectionStrip.hidden = false;
      selectionEyebrow.textContent = activeCategory !== 'all' ? activeCategory : query.length > 0 ? 'Suche aktiv' : 'Aktive Auswahl';
      selectionTitle.textContent =
        visibleCards.length === 1
          ? 'Ein klarer Treffer aus deiner aktuellen Auswahl.'
          : 'Drei sichtbare Treffer aus deiner aktuellen Auswahl.';

      selectionGrid.innerHTML = visibleCards.slice(0, 3).map((card) => {
        const imageSrc = card.querySelector('.product-image-wrap img')?.getAttribute('src') || '';
        const title = card.querySelector('.product-title')?.textContent || 'Produkt';
        const mode = card.querySelector('.product-mode-badge')?.textContent || 'Direkt greifen';
        const context = card.querySelector('.product-context-row span')?.textContent || '';
        const price = card.querySelector('.product-price-row strong')?.textContent || '';
        const href = card.querySelector('.product-image-wrap')?.getAttribute('href') || '#';
        const themeClass = Array.from(card.classList).find((className) => className.startsWith('theme-')) || 'theme-default';
        return (
          '<a class="catalog-selection-card ' + themeClass + '" href="' + href + '">' +
          renderDynamicImageMarkup({
            src: imageSrc,
            alt: title,
            width: 480,
            height: 480,
            sizes: '(min-width: 1100px) 18vw, 44vw',
            widths: [240, 360, 480, 640, 800],
          }) +
          '<div class="catalog-selection-copy">' +
          '  <p>' + mode + '</p>' +
          '  <strong>' + title + '</strong>' +
          '  <span>' + (context ? context + ' \xB7 ' : '') + price + '</span>' +
          '</div>' +
          '</a>'
        );
      }).join('');
    }

    function runFilter() {
      const query = (search.value || '').trim().toLowerCase();
      const visibleCards = [];

      cards.forEach((card) => {
        const category = card.getAttribute('data-category') || '';
        const haystack = card.getAttribute('data-name') || '';
        const categoryOk = activeCategory === 'all' || category === activeCategory;
        const queryOk = query.length === 0 || haystack.includes(query);
        const show = categoryOk && queryOk;
        card.style.display = show ? '' : 'none';
        if (show) {
          visibleCards.push(card);
        }
      });

      const sortedCards = [...visibleCards].sort((a, b) => compareCards(a, b, getSortValue()));
      sortedCards.forEach((card) => {
        grid.appendChild(card);
      });

      const hasFilters = query.length > 0 || activeCategory !== 'all' || getSortValue() !== 'featured';
      if (resetButton) {
        resetButton.hidden = !hasFilters;
      }

      if (contextNode) {
        const parts = [];
        if (activeCategory !== 'all') {
          parts.push(activeCategory);
        }
        if (query.length > 0) {
          parts.push('Suche: ' + query);
        }
        const contextCopy = parts.length > 0
          ? parts.join(' \xB7 ') + ' \xB7 Detailseiten mit Anwendung und Fit-Check'
          : 'Alle Produkte. Detailseiten mit Anwendung, FAQ und Fit-Check.';
        contextNode.innerHTML = '<strong>Bild vor Tiefgang</strong><small>' + escapeHtmlText(contextCopy) + '</small>';
      }

      if (countNode) {
        const countCopy = visibleCards.length === 0
          ? 'Filter loesen'
          : hasFilters ? 'Auswahl aktiv' : 'Sichtbare Auswahl';
        countNode.innerHTML = '<strong>' + escapeHtmlText(String(visibleCards.length) + ' Produkte') + '</strong><small>' + escapeHtmlText(countCopy) + '</small>';
      }

      if (emptyState) {
        const empty = visibleCards.length === 0;
        emptyState.hidden = !empty;
        grid.hidden = empty;
      }

      renderSelectionStrip(visibleCards, query, hasFilters);

      syncUrlState(query);
    }

    chips.forEach((chip) => {
      chip.addEventListener('click', () => {
        setActiveChip(chip.getAttribute('data-category-filter') || 'all');
        runFilter();
      });
      chip.addEventListener('keydown', (event) => {
        if (event.key !== 'ArrowLeft' && event.key !== 'ArrowRight' && event.key !== 'ArrowUp' && event.key !== 'ArrowDown') {
          return;
        }
        event.preventDefault();
        const currentIndex = chips.indexOf(chip);
        const nextIndex =
          event.key === 'ArrowLeft' || event.key === 'ArrowUp'
            ? (currentIndex - 1 + chips.length) % chips.length
            : (currentIndex + 1) % chips.length;
        const nextChip = chips[nextIndex];
        if (!nextChip) {
          return;
        }
        setActiveChip(nextChip.getAttribute('data-category-filter') || 'all');
        runFilter();
        nextChip.focus();
      });
    });

    if (resetButton) {
      resetButton.addEventListener('click', resetFilters);
    }
    if (emptyResetButton) {
      emptyResetButton.addEventListener('click', resetFilters);
    }

    const params = new URLSearchParams(window.location.search);
    const initialQuery = params.get('q') || '';
    const initialCategory = params.get('category') || 'all';
    const initialSort = params.get('sort') || 'featured';

    search.value = initialQuery;
    if (sort && Array.from(sort.options).some((option) => option.value === initialSort)) {
      sort.value = initialSort;
    }

    const hasCategoryChip = Array.from(chips).some(
      (chip) => (chip.getAttribute('data-category-filter') || 'all') === initialCategory,
    );
    setActiveChip(hasCategoryChip ? initialCategory : 'all');

    search.addEventListener('input', runFilter);
    if (sort) {
      sort.addEventListener('change', runFilter);
    }
    runFilter();
  }

  function bindUnifiedLoginForm() {
    const form = document.getElementById('loginForm');
    if (!form) {
      return;
    }

    const roleInput = document.getElementById('loginRole');
    const submitButton = document.getElementById('loginSubmit');
    const statusNode = document.getElementById('loginFormStatus');
    const roleButtons = Array.from(document.querySelectorAll('[data-login-role-btn]'));
    const previewCards = Array.from(document.querySelectorAll('[data-login-preview-card]'));
    const roleLabelNode = document.getElementById('loginRoleLabel');
    const roleHintNode = document.getElementById('loginRoleHint');

    function applyRole(role) {
      if (!roleInput || !submitButton) {
        return;
      }
      const normalized = role === 'admin' ? 'admin' : 'customer';
      roleInput.value = normalized === 'admin' ? 'admincenter' : 'kundencenter';
      submitButton.textContent = normalized === 'admin' ? 'Admin-Zugang anfragen' : 'Center-Zugang anfragen';
      updateRoleButtonState(roleButtons, normalized);
      updateRolePreviewState(previewCards, normalized);
      if (roleLabelNode) {
        roleLabelNode.textContent = normalized === 'admin' ? 'Admincenter' : 'Kundencenter';
      }
      if (roleHintNode) {
        roleHintNode.textContent = roleHintFor(normalized);
      }
      form.setAttribute('action', '/kontakt');
    }

    roleButtons.forEach((button) => {
      button.addEventListener('click', () => {
        applyRole(button.getAttribute('data-login-role-btn') || 'customer');
      });
      button.addEventListener('keydown', (event) => {
        if (event.key !== 'ArrowLeft' && event.key !== 'ArrowRight' && event.key !== 'ArrowUp' && event.key !== 'ArrowDown') {
          return;
        }
        event.preventDefault();
        const currentIndex = roleButtons.indexOf(button);
        const nextIndex =
          event.key === 'ArrowLeft' || event.key === 'ArrowUp'
            ? (currentIndex - 1 + roleButtons.length) % roleButtons.length
            : (currentIndex + 1) % roleButtons.length;
        const nextButton = roleButtons[nextIndex];
        if (!nextButton) {
          return;
        }
        applyRole(nextButton.getAttribute('data-login-role-btn') || 'customer');
        nextButton.focus();
      });
    });

    applyRole(roleInput ? roleInput.value : 'customer');

    form.addEventListener('submit', async (event) => {
      if (!form.reportValidity()) {
        event.preventDefault();
        return;
      }

      event.preventDefault();
      const data = new FormData(form);
      const roleValue = String(data.get('rolle') || 'kundencenter');
      const role = roleValue === 'admincenter' ? 'admin' : 'customer';
      const email = String(data.get('email') || '').trim();
      const note = String(data.get('hinweis') || '').trim();
      if (statusNode) {
        statusNode.textContent = loginRequestMessage(role, email);
      }
      form.setAttribute('action', '/kontakt');
      const roleField = form.querySelector('#loginRole');
      if (roleField instanceof HTMLInputElement) {
        roleField.value = role === 'admin' ? 'admincenter' : 'kundencenter';
      }
      try {
        await readStoreJson('/access-requests', {
          method: 'POST',
          body: JSON.stringify({
            email,
            role,
            note,
          }),
        });
      } catch {
        // Keep the contact fallback even when the API is temporarily unavailable.
      }
      window.location.href = roleContactHref(role, email, note);
    });
  }

  function renderCartPage() {
    const cartPage = document.getElementById('cartPage');
    if (!cartPage) {
      return;
    }

    const layout = document.getElementById('cartLayout');
    const empty = document.getElementById('cartEmpty');
    const list = document.getElementById('cartItemsList');
    const itemCountNode = document.getElementById('cartItemCount');
    const clearCartButton = document.getElementById('clearCartButton');
    const subtotalNode = document.getElementById('cartSubtotal');
    const shippingNode = document.getElementById('cartShipping');
    const totalNode = document.getElementById('cartGrandTotal');
    const checkoutTotalNode = document.getElementById('cartCheckoutTotal');
    const summaryVisual = document.getElementById('cartSummaryVisual');
    const summaryVisualImage = document.getElementById('cartSummaryVisualImage');
    const summaryVisualMode = document.getElementById('cartSummaryVisualMode');
    const summaryVisualTitle = document.getElementById('cartSummaryVisualTitle');
    const summaryVisualMeta = document.getElementById('cartSummaryVisualMeta');
    const summaryCluster = document.getElementById('cartSummaryCluster');
    const summaryClusterLabel = document.getElementById('cartSummaryClusterLabel');
    const summaryClusterPills = document.getElementById('cartSummaryClusterPills');

    if (!layout || !empty || !list || !subtotalNode || !shippingNode || !totalNode) {
      return;
    }

    const items = cartItemsDetailed();
    if (items.length === 0) {
      layout.hidden = true;
      empty.hidden = false;
      list.innerHTML = '';
      if (itemCountNode) {
        itemCountNode.textContent = '0';
      }
      subtotalNode.textContent = formatPrice(0);
      shippingNode.textContent = formatPrice(0);
      totalNode.textContent = formatPrice(0);
      if (checkoutTotalNode) {
        checkoutTotalNode.textContent = formatPrice(0);
      }
      if (summaryVisual) {
        summaryVisual.hidden = true;
        summaryVisual.className = 'cart-summary-visual';
      }
      if (summaryCluster) {
        summaryCluster.className = 'cart-summary-cluster';
      }
      if (summaryClusterLabel) {
        summaryClusterLabel.textContent = 'Jetzt gesamt';
      }
      if (summaryClusterPills) {
        summaryClusterPills.innerHTML =
          renderMetaCard('Lieferung', '24-48h') +
          renderMetaCard('Rueckgabe', 'Klar');
      }
      renderShippingProgress('cart', 0);
      renderDeliveryEstimate('cart', false);
      if (clearCartButton) {
        clearCartButton.onclick = null;
      }
      return;
    }

    layout.hidden = false;
    empty.hidden = true;

    list.innerHTML = '';
    items.forEach((item) => {
      const product = PRODUCT_BY_ID.get(item.sku || item.id) || {
        id: item.sku || item.id,
        slug: item.slug,
        name: item.title,
        category: item.category,
        priceEur: Number(item.unit_price_amount || 0) / 100,
        imageUrl: item.image_url,
        context: item.category,
        stock: item.stock || item.max_quantity || MAX_ITEM_QTY,
      };
      if (!product) {
        return;
      }
      const maxQty = Math.max(1, maxQtyForProduct(product));
      const stockCount = Number.isFinite(product.stock) ? Math.max(0, Math.round(product.stock)) : 0;
      const stockHint = productIsLowStock(product)
        ? 'Nur noch ' + stockCount + ' auf Lager'
        : stockCount + ' auf Lager' + (stockCount > maxQty ? ' \xB7 max. ' + maxQty + ' pro Bestellung' : '');
      const merchMode = merchModeForProduct(product);
      const merchThemeClass = merchThemeClassForProduct(product);

      const article = document.createElement('article');
      article.className = 'cart-item ' + merchThemeClass;
      article.setAttribute('data-cart-id', product.id);
      article.innerHTML =
        renderDynamicImageMarkup({
          src: product.imageUrl,
          alt: product.name,
          className: 'cart-item-image',
          width: 320,
          height: 320,
          sizes: '112px',
          widths: [112, 224, 320, 480],
        }) +
        '<div>' +
        '  <a class="cart-item-name" href="/products/' + product.slug + '">' + product.name + '</a>' +
        '  <p class="cart-item-sub"><span class="item-mode-pill">' + merchMode + '</span>' + product.category + '</p>' +
        '  <p class="cart-item-stock">' + stockHint + '</p>' +
        '  <div class="qty-control" role="group" aria-label="Menge fuer ' + product.name + '">' +
        '    <button type="button" data-cart-action="decrease" aria-label="Menge verringern">-</button>' +
        '    <span role="status" aria-live="polite">' + (item.quantity || item.qty) + '</span>' +
        '    <button type="button" data-cart-action="increase" aria-label="Menge erhoehen"' +
        ((item.quantity || item.qty) >= maxQty ? ' disabled aria-disabled="true"' : '') +
        '>+</button>' +
        '  </div>' +
        '  <button type="button" class="remove-btn" data-cart-action="remove">Entfernen</button>' +
        '</div>' +
        '<div class="cart-item-line-total">' + formatPrice((Number(item.line_total_amount || 0) / 100) || product.priceEur * Number(item.quantity || item.qty || 0)) + '</div>';

      list.appendChild(article);
    });

    const subtotal = Number(storeCartState && storeCartState.subtotal_amount ? storeCartState.subtotal_amount / 100 : 0) || cartSubtotal(readCart());
    const shipping = shippingCost(subtotal);
    if (itemCountNode) {
      itemCountNode.textContent = String(Number(storeCartState && storeCartState.item_count) || cartCount(readCart()));
    }
    subtotalNode.textContent = formatPrice(subtotal);
    shippingNode.textContent = shipping === 0 ? 'Gratis' : formatPrice(shipping);
    totalNode.textContent = formatPrice(subtotal + shipping);
    if (checkoutTotalNode) {
      checkoutTotalNode.textContent = formatPrice(subtotal + shipping);
    }
    const firstItem = items[0]
      ? PRODUCT_BY_ID.get(items[0].sku || items[0].id) || {
          imageUrl: items[0].image_url,
          name: items[0].title,
          category: items[0].category,
          context: items[0].category,
        }
      : null;
    if (summaryVisual && summaryVisualImage && summaryVisualMode && summaryVisualTitle && summaryVisualMeta && firstItem) {
      const merchMode = merchModeForProduct(firstItem);
      const merchThemeClass = merchThemeClassForProduct(firstItem);
      summaryVisual.hidden = false;
      summaryVisual.className = 'cart-summary-visual ' + merchThemeClass;
      setResponsiveImageAttributes(summaryVisualImage, firstItem.imageUrl, {
        width: 640,
        height: 640,
        sizes: '(min-width: 1100px) 360px, 92vw',
        widths: [320, 480, 640, 800, 960],
      });
      summaryVisualImage.alt = firstItem.name;
      summaryVisualMode.textContent = merchMode;
      summaryVisualTitle.textContent = firstItem.name;
      summaryVisualMeta.textContent =
        String(Number(storeCartState && storeCartState.item_count) || cartCount(readCart())) +
        ' Artikel insgesamt \xB7 ' +
        merchMode +
        ' \xB7 ' +
        (firstItem.context || firstItem.category) +
        ' \xB7 ' +
        (shipping === 0
          ? 'gratis Versand aktiv \xB7 ' + estimateDeliveryLabel()
          : 'Versand klar sichtbar \xB7 ' + estimateDeliveryLabel());
      if (summaryCluster) {
        summaryCluster.className = 'cart-summary-cluster ' + merchThemeClass;
      }
      if (summaryClusterLabel) {
        summaryClusterLabel.textContent = merchMode + ' gesamt';
      }
      if (summaryClusterPills) {
        summaryClusterPills.innerHTML =
          renderMetaCard('Modus', merchMode) +
          renderMetaCard('Kontext', firstItem.context || firstItem.category) +
          renderMetaCard('Lieferung', shipping === 0 ? 'Gratis Versand' : '24-48h');
      }
    } else if (summaryVisual) {
      summaryVisual.hidden = true;
      summaryVisual.className = 'cart-summary-visual';
    }
    renderShippingProgress('cart', subtotal);
    renderDeliveryEstimate('cart', true);

    if (clearCartButton) {
      clearCartButton.onclick = async () => {
        try {
          storeCartState = await readStoreJson('/cart', { method: 'DELETE' });
          syncCartBadges();
          renderCartDrawerState();
          renderCartPage();
          renderCheckoutSummary();
          showToast('Warenkorb geleert');
        } catch {
          showToast('Warenkorb konnte nicht geleert werden');
        }
      };
    }

    list.querySelectorAll('[data-cart-action]').forEach((control) => {
      control.addEventListener('click', () => {
        const row = control.closest('[data-cart-id]');
        if (!row) {
          return;
        }
        const id = row.getAttribute('data-cart-id');
        if (!id) {
          return;
        }

        const action = control.getAttribute('data-cart-action');
        const cart = readCart();
        const current = cart.find((entry) => entry.id === id);
        if (!current) {
          return;
        }

        if (action === 'increase') {
          updateCartItem(id, current.qty + 1);
        } else if (action === 'decrease') {
          updateCartItem(id, current.qty - 1);
        } else if (action === 'remove') {
          removeCartItem(id);
        }
      });
    });
  }

