function renderDocument({
  pathname,
  title,
  description,
  content,
  status = 200,
  headExtra = "",
  shareImage = "",
  structuredData = [],
  breadcrumbLabel = "",
  canonicalPath = pathname,
  metaType,
  robots,
  cacheControl = "public, max-age=120",
  responseHeaders = {},
  responseCookies = [],
  bootstrapState = null
}) {
  const canonicalUrl = absoluteUrl(canonicalPath);
  const metaImage = absoluteUrl(shareImage || homeVisualUrl("hero"));
  const resolvedMetaType = metaType || (pathname.startsWith("/products/") ? "product" : "website");
  const resolvedRobots = robots || defaultRobotsDirective(pathname, status);
  const breadcrumbItems = buildBreadcrumbItems(pathname, breadcrumbLabel || title.replace(/\s+\|.*/, ""));
  const jsonLdEntries = [
    buildOrganizationStructuredData(),
    pathname === "/" ? buildWebsiteStructuredData() : buildWebPageStructuredData(pathname, breadcrumbLabel || title.replace(/\s+\|.*/, ""), description),
    breadcrumbItems.length > 1 ? buildBreadcrumbStructuredData(breadcrumbItems) : null,
    ...structuredData
  ].filter(Boolean);
  const html = `<!doctype html>
<html lang="de">
  <head>
    <meta charset="UTF-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1" />
    <title>${escapeHtml(title)}</title>
    <meta name="description" content="${escapeHtml(description)}" />
    <meta name="theme-color" content="#fdfbf7" />
    <meta name="color-scheme" content="light" />
    <meta name="robots" content="${escapeHtml(resolvedRobots)}" />
    <link rel="canonical" href="${escapeHtml(canonicalUrl)}" />
    <link rel="manifest" href="/site.webmanifest" />
    <link rel="dns-prefetch" href="https://images.unsplash.com" />
    <link rel="preconnect" href="https://images.unsplash.com" crossorigin />
    <meta property="og:locale" content="de_DE" />
    <meta property="og:site_name" content="Delqhi" />
    <meta property="og:type" content="${escapeHtml(resolvedMetaType)}" />
    <meta property="og:title" content="${escapeHtml(title)}" />
    <meta property="og:description" content="${escapeHtml(description)}" />
    <meta property="og:url" content="${escapeHtml(canonicalUrl)}" />
    <meta property="og:image" content="${escapeHtml(metaImage)}" />
    <meta name="twitter:card" content="summary_large_image" />
    <meta name="twitter:title" content="${escapeHtml(title)}" />
    <meta name="twitter:description" content="${escapeHtml(description)}" />
    <meta name="twitter:image" content="${escapeHtml(metaImage)}" />
    ${jsonLdEntries.map((entry) => `<script type="application/ld+json">${serializeJsonLd(entry)}<\/script>`).join("\n    ")}
    ${headExtra}
    <style>${renderGlobalStyles()}</style>
  </head>
  <body>
    <a href="#mainContent" class="skip-link">Zum Inhalt springen</a>
    ${renderHeader(pathname)}
    <main id="mainContent" tabindex="-1">
      ${content}
    </main>
    ${renderCartDrawer()}
    ${renderFooter(pathname)}
    ${renderGlobalScript(bootstrapState)}
  </body>
</html>`;
  const headers = new Headers(
    defaultResponseHeaders({
      contentType: "text/html; charset=utf-8",
      cacheControl,
      extra: {
        "x-robots-tag": resolvedRobots,
        ...responseHeaders
      }
    })
  );
  responseCookies.forEach((cookieValue) => {
    headers.append("set-cookie", cookieValue);
  });
  return new Response(html, {
    status,
    headers
  });
}
